107→internal class SignParser<Output>(
108→    private val isNegativeSetter: (Output, Boolean) -> Unit,
109→    private val withPlusSign: Boolean,
110→    private val whatThisExpects: String,
111→) : ParserOperation<Output> {
112→    override fun consume(storage: Output, input: CharSequence, startIndex: Int): ParseResult {
113→        if (startIndex >= input.length)
114→            return ParseResult.Ok(startIndex)
115→        val char = input[startIndex]
116→        if (char == '-') {
117→            isNegativeSetter(storage, true)
118→            return ParseResult.Ok(startIndex + 1)
119→        }
120→        if (char == '+' && withPlusSign) {
121→            isNegativeSetter(storage, false)
122→            return ParseResult.Ok(startIndex + 1)
123→        }
124→        return ParseResult.Error(startIndex) { "Expected $whatThisExpects but got $char" }
125→    }
126→
127→    override fun toString(): String = whatThisExpects
128→}
