 16→ */
 17→internal class PlainStringParserOperation<Output>(val string: String) : ParserOperation<Output> {
 18→    init {
 19→        require(string.isNotEmpty()) { "Empty string is not allowed" }
 20→        require(!string[0].isAsciiDigit()) { "String '$string' starts with a digit" }
 21→        require(!string[string.length - 1].isAsciiDigit()) { "String '$string' ends with a digit" }
 22→    }
 23→
 24→    override fun consume(storage: Output, input: CharSequence, startIndex: Int): ParseResult {
 25→        if (startIndex + string.length > input.length)
 26→            return ParseResult.Error(startIndex) { "Unexpected end of input: yet to parse '$string'" }
 27→        for (i in string.indices) {
 28→            if (input[startIndex + i] != string[i]) return ParseResult.Error(startIndex) {
 29→                "Expected $string but got ${input.substring(startIndex, startIndex + i + 1)}"
 30→            }
 31→        }
 32→        return ParseResult.Ok(startIndex + string.length)
 33→    }
