 39→/**
 40→ * Greedily consumes as many digits as possible and redistributes them among [consumers].
 41→ *
 42→ * At most one consumer is allowed to have a variable length.
 43→ * If more digits are supplied than the sum of lengths of all consumers, this is the consumer that will receive the
 44→ * extra.
 45→ */
 46→internal class NumberSpanParserOperation<Output>(
 47→    val consumers: List<NumberConsumer<Output>>,
 48→) : ParserOperation<Output> {
 49→
 50→    private val minLength = consumers.sumOf { it.length ?: 1 }
 51→    private val isFlexible = consumers.any { it.length == null }
 52→
 53→    init {
 54→        require(consumers.all { (it.length ?: Int.MAX_VALUE) > 0 })
 55→        require(consumers.count { it.length == null } <= 1) {
 56→            val fieldNames = consumers.filter { it.length == null }.map { it.whatThisExpects }
 57→            "At most one variable-length numeric field in a row is allowed, but got several: $fieldNames. " +
 58→                "Parsing is undefined: for example, with variable-length month number " +
 59→                "and variable-length day of month, '111' can be parsed as Jan 11th or Nov 1st."
 60→        }
 61→    }
 62→
 63→    private val whatThisExpects: String
 64→        get() {
 65→            val consumerLengths = consumers.map {
 66→                when (val length = it.length) {
 67→                    null -> "at least one digit"
 68→                    else -> "$length digits"
 69→                } + " for ${it.whatThisExpects}"
 70→            }
 71→            return if (isFlexible) {
 72→                "a number with at least $minLength digits: $consumerLengths"
 73→            } else {
 74→                "a number with exactly $minLength digits: $consumerLengths"
 75→            }
 76→        }
 77→
 78→    override fun consume(storage: Output, input: CharSequence, startIndex: Int): ParseResult {
 79→        if (startIndex + minLength > input.length)
 80→            return ParseResult.Error(startIndex) { "Unexpected end of input: yet to parse $whatThisExpects" }
 81→        var digitsInRow = 0
 82→        while (startIndex + digitsInRow < input.length && input[startIndex + digitsInRow].isAsciiDigit()) {
 83→            ++digitsInRow
 84→        }
 85→        if (digitsInRow < minLength)
 86→            return ParseResult.Error(startIndex) {
 87→                "Only found $digitsInRow digits in a row, but need to parse $whatThisExpects"
 88→            }
 89→        var index = startIndex
 90→        for (i in consumers.indices) {
 91→            val length = consumers[i].length ?: (digitsInRow - minLength + 1)
 92→            val error = consumers[i].consume(storage, input, index, index + length)
 93→            if (error != null) {
 94→                val numberString = input.substring(index, index + length)
 95→                return ParseResult.Error(index) {
 96→                    "Can not interpret the string '$numberString' as ${consumers[i].whatThisExpects}: ${error.errorMessage()}"
 97→                }
 98→            }
 99→            index += length
100→        }
101→        return ParseResult.Ok(index)
102→    }
