144→ */
145→internal class StringSetParserOperation<Output>(
146→    strings: Collection<String>,
147→    private val setter: AssignableField<Output, String>,
148→    private val whatThisExpects: String,
149→) : ParserOperation<Output> {
150→
151→    // TODO: tries don't have good performance characteristics for small sets, add a special case for small sets
152→
153→    private class TrieNode(
154→        val children: MutableList<Pair<String, TrieNode>> = mutableListOf(),
155→        var isTerminal: Boolean = false
156→    )
157→
158→    private val trie = TrieNode()
159→
160→    init {
161→        for (string in strings) {
162→            require(string.isNotEmpty()) { "Found an empty string in $whatThisExpects" }
163→            var node = trie
164→            for (char in string) {
165→                val searchResult = node.children.binarySearchBy(char.toString()) { it.first }
166→                node = if (searchResult < 0) {
167→                    TrieNode().also { node.children.add(-searchResult - 1, char.toString() to it) }
168→                } else {
169→                    node.children[searchResult].second
170→                }
171→            }
172→            require(!node.isTerminal) { "The string '$string' was passed several times" }
173→            node.isTerminal = true
174→        }
175→        fun reduceTrie(trie: TrieNode) {
176→            for ((_, child) in trie.children) {
177→                reduceTrie(child)
178→            }
179→            val newChildren = mutableListOf<Pair<String, TrieNode>>()
180→            for ((key, child) in trie.children) {
181→                if (!child.isTerminal && child.children.size == 1) {
182→                    val (grandChildKey, grandChild) = child.children.single()
183→                    newChildren.add(key + grandChildKey to grandChild)
184→                } else {
185→                    newChildren.add(key to child)
186→                }
187→            }
188→            trie.children.clear()
189→            trie.children.addAll(newChildren.sortedBy { it.first })
190→        }
191→        reduceTrie(trie)
192→    }
193→
194→    override fun consume(storage: Output, input: CharSequence, startIndex: Int): ParseResult {
195→        var node = trie
196→        var index = startIndex
197→        var lastMatch: Int? = null
198→        loop@ while (index <= input.length) {
199→            if (node.isTerminal) lastMatch = index
200→            for ((key, child) in node.children) {
201→                if (input.startsWith(key, index)) {
202→                    node = child
203→                    index += key.length
204→                    continue@loop
205→                }
206→            }
207→            break // nothing found
208→        }
209→        return if (lastMatch != null) {
210→            setter.setWithoutReassigning(storage, input.substring(startIndex, lastMatch), startIndex, lastMatch)
211→        } else {
212→            ParseResult.Error(startIndex) { "Expected $whatThisExpects but got ${input.substring(startIndex, index)}" }
213→        }
214→    }
215→}
